"/**
 * Accretion disk texture — drawn on a full square canvas.
 * We use PlaneGeometry so UVs are 0→1 across the plane:
 * horizontal gradient (left=inner hot, right=outer cool) × vertical soft band.
 */
function createDiskTex(
  innerHex: string,
  midHex:   string,
  outerHex: string,
): THREE.CanvasTexture {
  const W = 512, H = 64;
  const canvas = document.createElement('canvas');
  canvas.width = W; canvas.height = H;
  const ctx = canvas.getContext('2d')!;
  ctx.clearRect(0, 0, W, H);

  // Horizontal: inner (hot) → outer (cool)
  const horiz = ctx.createLinearGradient(0, 0, W, 0);
  horiz.addColorStop(0.00, rgba(innerHex, 0.0));
  horiz.addColorStop(0.05, rgba(innerHex, 0.9));
  horiz.addColorStop(0.30, rgba(midHex,   0.85));
  horiz.addColorStop(0.65, rgba(outerHex, 0.55));
  horiz.addColorStop(0.90, rgba(outerHex, 0.12));
  horiz.addColorStop(1.00, rgba(outerHex, 0.0));
  ctx.fillStyle = horiz;
  ctx.fillRect(0, 0, W, H);

  // Vertical: bright centre band, fade top+bottom
  const vert = ctx.createLinearGradient(0, 0, 0, H);
  vert.addColorStop(0.00, 'rgba(0,0,0,0)');
  vert.addColorStop(0.25, 'rgba(0,0,0,0.4)');
  vert.addColorStop(0.50, 'rgba(0,0,0,0)');   // transparent = keep colour
  vert.addColorStop(0.75, 'rgba(0,0,0,0.4)');
  vert.addColorStop(1.00, 'rgba(0,0,0,0)');
  ctx.globalCompositeOperation = 'destination-out';
  ctx.fillStyle = vert;
  ctx.fillRect(0, 0, W, H);

  return new THREE.CanvasTexture(canvas);
}

function rgba(hex: string, a: number) {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return `rgba(${r},${g},${b},${a})`;
}"
